<template>
  <div>
    <el-card>
      <div slot="header">我的订单</div>
      <el-table :data="list" border stripe v-loading="loading">
        <el-table-column prop="orderNo" label="订单号" width="180" />
        <el-table-column prop="productName" label="商品" />
        <el-table-column prop="quantity" label="数量" width="60" />
        <el-table-column prop="actualAmount" label="总价(元)" width="90" />
        <el-table-column prop="status" label="状态" width="80">
          <template slot-scope="scope">
            <el-tag :type="scope.row.status===1?'success':scope.row.status===2?'info':'warning'" size="small">
              {{ scope.row.status===0?'待付款':scope.row.status===1?'已付款':'已取消' }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="createTime" label="下单时间" width="160" />
        <el-table-column label="操作" width="130" align="center">
          <template slot-scope="scope">
            <div class="table-action-btns">
              <el-button v-if="scope.row.status===0" size="mini" type="danger" @click="cancelOrder(scope.row)">取消订单</el-button>
            </div>
          </template>
        </el-table-column>
      </el-table>
      <el-pagination style="margin-top:15px;text-align:right" background layout="total, prev, pager, next"
        :total="total" :page-size="query.pageSize" :current-page.sync="query.pageNum" @current-change="loadData" />
    </el-card>
  </div>
</template>
<script>
import request from '@/utils/request'
export default {
  data() {
    return { list: [], total: 0, loading: false, query: { pageNum: 1, pageSize: 10 } }
  },
  created() { this.loadData() },
  methods: {
    loadData() {
      this.loading = true
      const user = JSON.parse(sessionStorage.getItem('loginUser') || '{}')
      request.get('/api/order', { params: { ...this.query, studentId: user.id } }).then(res => {
        this.list = res.data.records; this.total = res.data.total
      }).finally(() => { this.loading = false })
    },
    cancelOrder(row) {
      this.$confirm('确定取消该订单?', '提示', { type: 'warning' }).then(() => {
        request.put('/api/order', { ...row, status: 2 }).then(() => { this.$message.success('已取消'); this.loadData() })
      }).catch(() => {})
    }
  }
}
</script>
